+  value: unknown,
+  fieldName: string,
+  maxLength: number,
+): string {
+  if (typeof value !== "string") {
+    throw new HttpError(400, "VALIDATION_ERROR", `${fieldName} is required.`);
+  }
+
+  const normalized = value.trim();
+  if (normalized.length === 0) {
